     5	func metricDefinitionFromExec(def ddxexec.Definition) (Definition, error) {
     6		out := Definition{
     7			DefinitionID: def.ID,
     8			MetricID:     metricArtifactID(def.ArtifactIDs),
     9			Command:      append([]string{}, def.Executor.Command...),
    10			Cwd:          def.Executor.Cwd,
    11			Env:          cloneStringMap(def.Executor.Env),
    12			Thresholds: Thresholds{
    13				Warn:    def.Evaluation.Thresholds.WarnMS,
    14				Ratchet: def.Evaluation.Thresholds.RatchetMS,
    15				Unit:    "",
    16			},
    17			Comparison: def.Evaluation.Comparison,
    18			Active:     def.Active,
    19			CreatedAt:  def.CreatedAt,
    20		}
    21		if def.Result.Metric != nil {
    22			out.Thresholds.Unit = def.Result.Metric.Unit
    23		}
    24		return out, nil
    25	}
